import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { productDatabase } from '../constants/products';
import '../assets/styles/Products.css';

const Products = () => {
    const { addToCart } = useCart();
    const navigate = useNavigate();

    const allProducts = Object.keys(productDatabase).map(key => ({
        id: key,
        ...productDatabase[key]
    }));

    const handleBuyNow = async (e, product) => {
        e.preventDefault();
        e.stopPropagation();

        await addToCart({
            productId: product.id,
            title: product.title,
            price: product.variants['500g'].price, // Default to 500g for quick shop
            image: product.images[0],
            weight: '500g',
            quantity: 1
        });
        navigate('/checkout');
    };

    const handleAddToCart = (e, product) => {
        e.preventDefault();
        e.stopPropagation();

        addToCart({
            productId: product.id,
            title: product.title,
            price: product.variants['500g'].price,
            image: product.images[0],
            weight: '500g',
            quantity: 1
        });
    };

    return (
        <div className="all-products-page">
            <header className="products-hero">
                <div className="hero-overlay"></div>
                <div className="hero-content">
                    <span className="hero-tag">OUR COLLECTION</span>
                    <h1>Heritage Harvest Atelier</h1>
                    <p>Pure, chemical-free, and ethically sourced. Explore our full range of traditional essentials.</p>
                </div>
            </header>

            <div className="products-container">
                <div className="products-controls">
                    <div className="result-count">{allProducts.length} artisanal products</div>
                </div>

                <div className="products-grid">
                    {allProducts.map((product) => (
                        <Link to={`/product/${product.id}`} key={product.id} className="product-card" style={{ textDecoration: 'none' }}>
                            <div className="card-image-wrap">
                                <img src={product.images[0]} alt={product.title} />
                                <div className="card-tag">{product.tag}</div>
                            </div>
                            <div className="card-body">
                                <div className="card-header">
                                    <h3>{product.title}</h3>
                                    <span className="price-tag">₹{product.variants['500g'].price}</span>
                                </div>
                                <p className="card-desc">{product.description}</p>
                                <div className="card-footer">
                                    <button 
                                        className="btn-add-cart" 
                                        onClick={(e) => handleAddToCart(e, product)}
                                    >
                                        ADD TO CART
                                    </button>
                                    <button 
                                        className="btn-buy-now" 
                                        onClick={(e) => handleBuyNow(e, product)}
                                    >
                                        BUY NOW
                                    </button>
                                </div>
                            </div>
                        </Link>
                    ))}
                </div>
            </div>
        </div>
    );
};

export default Products;
